python3 -c "
import os, json
log = f'/tmp/.travel_scrapping_rtk_log_{os.getppid()}'
if not os.path.exists(log):
    raise SystemExit(0)
lines = open(log).read().strip().splitlines()
if not lines:
    raise SystemExit(0)
seen = {}
for line in lines:
    parts = line.split('|', 1)
    tool, cmd = parts if len(parts) == 2 else (parts[0], '')
    if tool not in seen:
        seen[tool] = []
    seen[tool].append(cmd)
summary = 'RTK non respecte cette session :\n'
for tool, cmds in seen.items():
    for cmd in cmds:
        summary += f'- {tool} nu : {cmd}\n'
print(json.dumps({'hookSpecificOutput': {'hookEventName': 'Stop', 'additionalContext': summary}}))
" 2>/dev/null || true
